#include <iostream>

class Rectangle
{
public:
    int width{};
    int height{};

    int area() const { return width * height; }
};

class Box : public Rectangle
{
public:
    int depth{};

    int volume() const { return width * height * depth; }
};

int main()
{
    int width{};
    int height{};
    int depth{};
    std::cin >> width >> height >> depth;

    Box box{};
    box.width = width;
    box.height = height;
    box.depth = depth;

    std::cout << "Rectangle " << box.width << 'x' << box.height
              << " area " << box.area() << '\n';
    std::cout << "Box " << box.width << 'x' << box.height << 'x' << box.depth
              << " volume " << box.volume() << '\n';

    return 0;
}

