#include <iostream>
#include <string>

class Employee
{
public:
    std::string name{};
    int baseSalary{};
};

class Manager : public Employee
{
public:
    int bonus{};
};

class Director : public Manager
{
public:
    int stock{};

    int total() const { return baseSalary + bonus + stock; }
};

int main()
{
    std::string name{};
    int baseSalary{};
    int bonus{};
    int stock{};
    std::cin >> name >> baseSalary >> bonus >> stock;

    Director d{};
    d.name = name;
    d.baseSalary = baseSalary;
    d.bonus = bonus;
    d.stock = stock;

    std::cout << "Director: " << d.name << '\n';
    std::cout << "base " << d.baseSalary << ", bonus " << d.bonus
              << ", stock " << d.stock << '\n';
    std::cout << "total " << d.total() << '\n';

    return 0;
}
